// b-book予約確定メールからゲスト名/メール/日程/Zoom URLを抽出
const t = String($json.text || $json.snippet || $json.html || '');
const subj = String($json.subject || '');
const pick = (re, s) => { const m = (s || t).match(re); return m ? m[1].trim() : ''; };
const guestLine = pick(/【ゲスト】\s*([^\n]+)/);
let name = pick(/^\s*([^|｜]+?)様/, guestLine);
if (!name) name = pick(/新規受付[:：]\s*([^\s/／]+?)様/, subj);
const email = pick(/([\w.+-]+@[\w.-]+\.[A-Za-z]{2,})/, guestLine);
const datetime = pick(/【日程】\s*([^\n]+)/);
const zoomUrl = pick(/(https?:\/\/[^\s<>"']*zoom\.us\/[^\s<>"']+)/);
const manageUrl = pick(/【予約管理URL】\s*(https?:\/\/[^\s<>"']+)/);
const booking = { name, email, datetime, zoomUrl, manageUrl };
return [{ json: { booking } }];
